mapper.select:
        SELECT 
            (SELECT COUNT(1) FROM boss_interview 

                    AND tenant_id = #{tenantId}


                    AND create_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as totalInterviewees, # 总面试者数量
            (SELECT COUNT(1) FROM boss_interview_arrangement 
                state in (4, 6, 7, 9)

                    AND tenant_id = #{tenantId}


                    AND interview_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND interview_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as hiredCount, # 通过面试的数量
            (SELECT COUNT(1) FROM boss_interview_arrangement 
                state = 3

                    AND tenant_id = #{tenantId}


                    AND interview_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND interview_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as pendingInterviewCount, # 待面试的数量
            (SELECT COUNT(1) FROM boss_interview 
                state = 1

                    AND tenant_id = #{tenantId}


                    AND create_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as interviewingCount, # 待面试者数量
            (SELECT COUNT(1) FROM boss_interview_arrangement 
                state = 5

                    AND tenant_id = #{tenantId}


                    AND interview_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND interview_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as failedCount, # 面试失败数量
            (SELECT COUNT(1) FROM boss_interview_arrangement 
                state = 7

                    AND tenant_id = #{tenantId}


                    AND interview_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND interview_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as rejectedCount, # 拒绝入职的数量
            (SELECT COUNT(1) FROM boss_person_require 
                state in ('inRecruitment', 'pass')

                    AND tenant_id = #{tenantId}


                    AND create_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as totalRequirements, # 总需求数量
            (SELECT COUNT(1) FROM boss_interview_regular_worker 
                state = 'pass'

                    AND tenant_id = #{tenantId}


                    AND regular_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND regular_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as regularWorkerCount, # 转正的数量
            (SELECT COUNT(1) FROM boss_interview_quit 
                state = 'pass'

                    AND tenant_id = #{tenantId}


                    AND leave_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND leave_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as quitCount # 离职的数量

SELECT state, COUNT(1) as count, ROUND(COUNT(1) * 100.0 / (SELECT COUNT(1) FROM boss_interview
AND tenant_id = #{tenantId}
AND create_time >= CONCAT(#{startDate}, ' 00:00:00')
AND create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)
), 2) as percentage FROM boss_interview
AND tenant_id = #{tenantId}
AND create_time >= CONCAT(#{startDate}, ' 00:00:00')
AND create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)
GROUP BY state ORDER BY state

SELECT a.`year_month` yearMonth, COUNT(1) as totalInterviewees, SUM(CASE WHEN b.state = 2 THEN 1 ELSE 0 END) as hiredCount, # 面试通过数量 SUM(CASE WHEN b.state = 0 THEN 1 ELSE 0 END) as pendingCount, # 待面试数量 SUM(CASE WHEN b.state = 1 THEN 1 ELSE 0 END) as interviewingCount, # 面试中数量 SUM(CASE WHEN b.state = 3 THEN 1 ELSE 0 END) as failedCount, # 面试失败数量 SUM(CASE WHEN b.state = 4 THEN 1 ELSE 0 END) as rejectedCount # 拒绝入职数量 FROM (SELECT CONCAT(#{year}, '-01') AS `year_month` UNION SELECT CONCAT(#{year}, '-02') AS `year_month` UNION SELECT CONCAT(#{year}, '-03') AS `year_month` UNION SELECT CONCAT(#{year}, '-04') AS `year_month` UNION SELECT CONCAT(#{year}, '-05') AS `year_month` UNION SELECT CONCAT(#{year}, '-06') AS `year_month` UNION SELECT CONCAT(#{year}, '-07') AS `year_month` UNION SELECT CONCAT(#{year}, '-08') AS `year_month` UNION SELECT CONCAT(#{year}, '-09') AS `year_month` UNION SELECT CONCAT(#{year}, '-10') AS `year_month` UNION SELECT CONCAT(#{year}, '-11') AS `year_month` UNION SELECT CONCAT(#{year}, '-12') AS `year_month`) a LEFT JOIN boss_interview b ON date_format(b.create_time, '%Y-%m') = a.`year_month`
AND b.tenant_id = #{tenantId}
GROUP BY a.`year_month`

        SELECT 
            (SELECT COUNT(1) FROM boss_interview_regular_worker 
                state in ('pass', 'inExamine')

                    AND tenant_id = #{tenantId}


                    AND create_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as totalRegularCount, # 总转正申请数量
            (SELECT COUNT(1) FROM boss_interview_regular_worker 
                state = 'pass'

                    AND tenant_id = #{tenantId}


                    AND create_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as approvedRegularCount, # 已通过转正数量
            (SELECT COUNT(1) FROM boss_interview_regular_worker 
                state = 'inExamine'

                    AND tenant_id = #{tenantId}


                    AND create_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as pendingRegularCount, # 待审核转正数量
            (SELECT COUNT(1) FROM boss_interview_quit 
                state in ('pass', 'inExamine')

                    AND tenant_id = #{tenantId}


                    AND create_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as totalQuitCount, # 总离职申请数量
            (SELECT COUNT(1) FROM boss_interview_quit 
                state = 'pass'

                    AND tenant_id = #{tenantId}


                    AND create_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as approvedQuitCount, # 已通过离职数量
            (SELECT COUNT(1) FROM boss_interview_quit 
                state = 'inExamine'

                    AND tenant_id = #{tenantId}


                    AND create_time >= CONCAT(#{startDate}, ' 00:00:00')


                    AND create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

			) as pendingQuitCount # 待审核离职数量
